package main

import (
    "fmt"
    "log"
    "net/http"
    "time"
)

// ---- Middleware functions ----

// ---- Logging middleware ----
func loggingMiddleware(next http.HandlerFunc) http.HandlerFunc {
    return func(w http.ResponseWriter, r *http.Request) {
        start := time.Now()

        // Log the request
        log.Printf("Started %s %s", r.Method, r.URL.Path)

        // Call the next handler
        next(w, r)

        // Log after the request
        log.Printf("Completed %s %s in %v", r.Method, r.URL.Path, time.Since(start))
    }
}

// ---- Auth middleware ----
func authMiddleware(next http.HandlerFunc) http.HandlerFunc {
    return func(w http.ResponseWriter, r *http.Request) {
        token := r.Header.Get("Authorization")
        if token == "" {
            http.Error(w, "Unauthorized", http.StatusUnauthorized)
            return
        }

        // In real app, validate token here
        if token != "Bearer secret" {
            http.Error(w, "Invalid token", http.StatusUnauthorized)
            return
        }

        next(w, r)
    }
}

// ---- Rate limiting middleware ----
type RateLimiter struct {
    requests int
    limit    int
    reset    time.Time
}

func rateLimitMiddleware(next http.HandlerFunc) http.HandlerFunc {
    limiter := &RateLimiter{
        limit: 10,
        reset: time.Now().Add(time.Minute),
    }

    return func(w http.ResponseWriter, r *http.Request) {
        // Reset if time expired
        if time.Now().After(limiter.reset) {
            limiter.requests = 0
            limiter.reset = time.Now().Add(time.Minute)
        }

        limiter.requests++

        if limiter.requests > limiter.limit {
            http.Error(w, "Rate limit exceeded", http.StatusTooManyRequests)
            return
        }

        next(w, r)
    }
}

// ---- Recovery middleware ----
func recoveryMiddleware(next http.HandlerFunc) http.HandlerFunc {
    return func(w http.ResponseWriter, r *http.Request) {
        defer func() {
            if err := recover(); err != nil {
                log.Printf("Recovered from panic: %v", err)
                http.Error(w, "Internal server error", http.StatusInternalServerError)
            }
        }()

        next(w, r)
    }
}

// ---- Chain middleware ----
func chainMiddleware(handler http.HandlerFunc, middlewares ...func(http.HandlerFunc) http.HandlerFunc) http.HandlerFunc {
    for _, middleware := range middlewares {
        handler = middleware(handler)
    }
    return handler
}

// ---- Handlers ----
func helloHandler(w http.ResponseWriter, r *http.Request) {
    fmt.Fprintf(w, "Hello, Player!")
}

func secretHandler(w http.ResponseWriter, r *http.Request) {
    fmt.Fprintf(w, "Secret data!")
}

func panicHandler(w http.ResponseWriter, r *http.Request) {
    panic("Something went wrong!")
}

func main() {
    // ---- Apply middleware ----
    http.HandleFunc("/", loggingMiddleware(helloHandler))
    http.HandleFunc("/secret", chainMiddleware(secretHandler, loggingMiddleware, authMiddleware))
    http.HandleFunc("/rate", chainMiddleware(helloHandler, loggingMiddleware, rateLimitMiddleware))
    http.HandleFunc("/panic", chainMiddleware(panicHandler, loggingMiddleware, recoveryMiddleware))

    fmt.Println("Server starting on :8080")
    fmt.Println("Routes:")
    fmt.Println("  GET /")
    fmt.Println("  GET /secret (requires Authorization: Bearer secret)")
    fmt.Println("  GET /rate (limited to 10 requests/min)")
    fmt.Println("  GET /panic (tests recovery)")

    http.ListenAndServe(":8080", nil)
}

